function ExpenseLog() {
  const [expenses, setExpenses] = React.useState([
    { id: 1, name: 'Coffee', amount: 5.50, category: 'Food' },
    { id: 2, name: 'Uber', amount: 12.30, category: 'Transport' },
    { id: 3, name: 'Groceries', amount: 67.20, category: 'Food' }
  ]);
  const [name, setName] = React.useState('');
  const [amount, setAmount] = React.useState('');
  const [category, setCategory] = React.useState('Food');

  const addExpense = () => {
    if (!name || !amount) return;
    setExpenses([...expenses, { id: Date.now(), name, amount: parseFloat(amount), category }]);
    setName('');
    setAmount('');
  };

  const total = expenses.reduce((s, e) => s + e.amount, 0);
  const cats = [...new Set(expenses.map(e => e.category))];

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#ffffff', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column', color: '#1e293b' }}>
      <h2 style={{ margin: '0 0 12px', fontSize: 18 }}>Expense Log</h2>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        <input placeholder="Name" value={name} onChange={e => setName(e.target.value)} style={{ flex: 1, padding: 8, borderRadius: 6, border: '1px solid #cbd5e1', fontSize: 13 }} />
        <input placeholder="$" type="number" value={amount} onChange={e => setAmount(e.target.value)} style={{ width: 60, padding: 8, borderRadius: 6, border: '1px solid #cbd5e1', fontSize: 13 }} />
        <select value={category} onChange={e => setCategory(e.target.value)} style={{ padding: 8, borderRadius: 6, border: '1px solid #cbd5e1', fontSize: 13 }}>
          {cats.map(c => <option key={c}>{c}</option>)}
          <option>Other</option>
        </select>
        <button onClick={addExpense} style={{ padding: '8px 12px', borderRadius: 6, border: 'none', background: '#2563eb', color: '#fff', fontSize: 13, cursor: 'pointer' }}>Add</button>
      </div>
      <div style={{ flex: 1, overflow: 'auto' }}>
        {expenses.map(e => (
          <div key={e.id} style={{ display: 'flex', justifyContent: 'space-between', padding: '8px 0', borderBottom: '1px solid #e2e8f0', fontSize: 14 }}>
            <span>{e.name} <span style={{ fontSize: 11, color: '#64748b', background: '#f1f5f9', padding: '2px 6px', borderRadius: 4 }}>{e.category}</span></span>
            <span style={{ fontWeight: 600 }}>${e.amount.toFixed(2)}</span>
          </div>
        ))}
      </div>
      <div style={{ marginTop: 12, fontSize: 18, fontWeight: 700, textAlign: 'right' }}>Total: ${total.toFixed(2)}</div>
    </div>
  );
}
render(<ExpenseLog/>);
